using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set AI:ApiKey in configuration or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

builder.Services.AddSingleton<NoteService>();

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var noteService = host.Services.GetRequiredService<NoteService>();

// Define tools
var searchTool = AIFunctionFactory.Create(
    (string query) =>
    {
        Console.WriteLine($"  [Searching web for: \"{query}\"]");
        // Simulated web search results
        return query.ToLowerInvariant() switch
        {
            var q when q.Contains("quantum computing") =>
                """
                1. Quantum computers use qubits that can exist in superposition states.
                2. Google achieved quantum supremacy in 2019 with their Sycamore processor.
                3. IBM plans to deliver 100,000-qubit systems by 2033.
                4. Key applications include cryptography, drug discovery, and optimization.
                5. Current challenges include error correction and maintaining coherence.
                """,
            var q when q.Contains("artificial intelligence") || q.Contains(" ai ") =>
                """
                1. Large language models have transformed NLP since GPT-3 in 2020.
                2. AI agents with tool-use capabilities are a major research focus in 2025-2026.
                3. Regulation frameworks are being adopted worldwide (EU AI Act, US executive orders).
                4. Multimodal models now handle text, images, audio, and video.
                5. Energy consumption of AI training remains a growing concern.
                """,
            _ =>
                $"""
                1. "{query}" is an active area of research.
                2. Recent developments show significant progress in this field.
                3. Multiple organizations are investing in related technologies.
                4. Challenges remain around scalability and practical applications.
                5. Expert consensus suggests continued growth over the next decade.
                """
        };
    },
    "search_web",
    "Searches the web for information on a given query. Returns a list of relevant results.");

var addNoteTool = AIFunctionFactory.Create(
    (string title, string content) =>
    {
        noteService.AddNote(title, content);
        Console.WriteLine($"  [Note saved: \"{title}\"]");
        return $"Note '{title}' saved successfully.";
    },
    "add_note",
    "Saves a research note with a title and content for later reference.");

var getNotesTool = AIFunctionFactory.Create(
    () =>
    {
        var notes = noteService.GetNotes();
        if (notes.Count == 0) return "No notes saved yet.";
        return string.Join("\n\n", notes.Select(n => $"## {n.Title}\n{n.Content}"));
    },
    "get_notes",
    "Retrieves all saved research notes.");

// Create the agent
var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Description = "An AI research agent that searches the web and takes notes to summarize findings.",
    Instructions = """
        You are a research agent. Your goal is to research the given topic thoroughly.

        Follow these steps:
        1. Search the web for information on the topic (make 2-3 searches with different queries).
        2. Save key findings as notes using the add_note tool.
        3. Review your notes using get_notes.
        4. Provide a final comprehensive summary of your research.

        Be thorough but concise in your research.
        """,
};

// Run the agent
Console.WriteLine("═══════════════════════════════════════════");
Console.WriteLine("       AI Research Agent");
Console.WriteLine("═══════════════════════════════════════════");
Console.Write("\nEnter a topic to research (or press Enter for default): ");
var topic = Console.ReadLine();
if (string.IsNullOrWhiteSpace(topic))
    topic = "quantum computing";

Console.WriteLine($"\nResearching: {topic}\n");

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
    Tools = [searchTool, addNoteTool, getNotesTool],
    ModelOptions = new ChatOptions { Temperature = 0f, MaxOutputTokens = 2048 },
};

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n═══════════════════════════════════════════");
Console.WriteLine($"Research complete. {noteService.GetNotes().Count} note(s) saved.");
Console.WriteLine("═══════════════════════════════════════════");

// --- Supporting types ---

public class NoteService
{
    private readonly List<Note> _notes = [];

    public void AddNote(string title, string content) =>
        _notes.Add(new Note(title, content, DateTime.UtcNow));

    public IReadOnlyList<Note> GetNotes() => _notes.AsReadOnly();
}

public record Note(string Title, string Content, DateTime CreatedAt);

